use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

#[derive(Clone)]
pub struct Inventory {
    items: Arc<Mutex<HashMap<String, u32>>>,
}

impl Inventory {
    pub fn new(initial: HashMap<String, u32>) -> Self {
        Self {
            items: Arc::new(Mutex::new(initial)),
        }
    }

    pub fn check_stock(&self, item: &str) -> u32 {
        let items = self.items.lock().unwrap();
        *items.get(item).unwrap_or(&0)
    }

    pub fn decrement(&self, item: &str, qty: u32) -> bool {
        let mut items = self.items.lock().unwrap();
        match items.get_mut(item) {
            Some(stock) if *stock >= qty => {
                *stock -= qty;
                true
            }
            _ => false,
        }
    }

    pub fn update_concurrently(&self, item: &str, qty: u32, threads: usize) -> Vec<bool> {
        let mut handles = Vec::with_capacity(threads);
        let item = Arc::new(item.to_string());

        for _ in 0..threads {
            let inventory = self.clone();
            let item = Arc::clone(&item);
            handles.push(thread::spawn(move || {
                let _ = inventory.check_stock(&item);
                inventory.decrement(&item, qty)
            }));
        }

        handles
            .into_iter()
            .map(|h| h.join().unwrap())
            .collect()
    }
}